46	          isExpanded={isMenuOpen}
47	          variant={ButtonVariant.primary}
48	        >
49	          {t('Create storage map')}
50	        </MenuToggle>
51	      )}
52	      shouldFocusFirstItemOnOpen={false}
53	      popperProps={{
54	        position: 'right',
55	      }}
56	    >
57	      <DropdownList>
58	        <DropdownItem
59	          key="form"
60	          onClick={() => {
61	            trackEvent(TELEMETRY_EVENTS.STORAGE_MAP_CREATE_STARTED, {
62	              creationMethod: CreationMethod.Form,
63	              namespace,
64	            });
65	            navigate(`/k8s/storageMaps/create/form`);
66	          }}
67	        >
68	          {t('Create with form')}
69	        </DropdownItem>
70	
71	        <DropdownItem
72	          key="yaml"
73	          onClick={() => {
74	            trackEvent(TELEMETRY_EVENTS.STORAGE_MAP_CREATE_STARTED, {
75	              creationMethod: CreationMethod.YamlEditor,
76	              namespace,
77	            });
78	            navigate(`${storageMapsListUrl}/~new`);
79	          }}
80	        >
81	          {t('Create with YAML')}
82	        </DropdownItem>
83	      </DropdownList>
84	    </Dropdown>
85	  );
86	};
87	
88	export default StorageMapsAddButton;

